   333→/// Tally - add a new Tack to a Pace
   334→///
   335→/// Prepends a new Tack with state transition and/or plan refinement.
   336→pub fn jjrg_tally(gallops: &mut jjrg_Gallops, args: jjrg_TallyArgs) -> Result<(), String> {
   337→    // Parse and normalize coronet
   338→    let coronet = Coronet::jjrf_parse(&args.coronet)
   339→        .map_err(|e| format!("Invalid coronet: {}", e))?;
   340→    let coronet_key = coronet.jjrf_display();
   341→
   342→    // Extract parent Firemark
   343→    let firemark = coronet.jjrf_parent_firemark();
   344→    let firemark_key = firemark.jjrf_display();
   345→
   346→    // Verify Heat exists
   347→    let heat = gallops.heats.get_mut(&firemark_key)
   348→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   349→
   350→    // Verify Pace exists
   351→    let pace = heat.paces.get_mut(&coronet_key)
   352→        .ok_or_else(|| format!("Pace '{}' not found", coronet_key))?;
   353→
   354→    // Read current Tack
   355→    let current_tack = pace.tacks.first()
   356→        .ok_or_else(|| "Pace has no tacks (should never happen)".to_string())?;
   357→
   358→    // Check for the new-spec-invalidates-bridled condition:
   359→    // If pace is currently bridled AND new spec text is provided AND no explicit --state,
   360→    // then auto-reset to rough (new spec invalidates old direction)
   361→    let auto_reset_to_rough = args.state.is_none()
   362→        && matches!(current_tack.state, jjrg_PaceState::Bridled)
   363→        && args.text.is_some();
   364→
   365→    // Determine new state
   366→    let new_state = if auto_reset_to_rough {
   367→        jjrg_PaceState::Rough
   368→    } else {
   369→        args.state.clone().unwrap_or_else(|| current_tack.state.clone())
   370→    };
   371→
   372→    // Determine new direction
   373→    let new_direction = match (&args.state, &new_state) {
   374→        // State explicitly set to bridled: direction required
   375→        (Some(jjrg_PaceState::Bridled), _) => {
   376→            match &args.direction {
   377→                Some(d) if !d.is_empty() => Some(d.clone()),
   378→                Some(_) => return Err("direction must not be empty when state is bridled".to_string()),
   379→                None => return Err("direction is required when state is bridled".to_string()),
   380→            }
   381→        }
   382→        // State explicitly set to something other than bridled: direction forbidden
   383→        (Some(_), _) => {
   384→            if args.direction.is_some() {
   385→                return Err("direction must be absent when state is not bridled".to_string());
   386→            }
   387→            None
   388→        }
   389→        // Auto-reset to rough: no direction
   390→        _ if auto_reset_to_rough => None,
   391→        // State inherited and was bridled: inherit direction
   392→        (None, jjrg_PaceState::Bridled) => {
   393→            args.direction.or_else(|| current_tack.direction.clone())
   394→        }
   395→        // State inherited and was not bridled: no direction
   396→        (None, _) => None,
   397→    };
   398→
   399→    // Determine new text
   400→    let new_text = args.text.unwrap_or_else(|| current_tack.text.clone());
   401→    if new_text.is_empty() {
   402→        return Err("text must not be empty".to_string());
   403→    }
   404→
   405→    // Determine new silks
   406→    let new_silks = args.silks.unwrap_or_else(|| current_tack.silks.clone());
   407→
   408→    // Create new Tack
   409→    let new_tack = jjrg_make_tack(
   410→        new_state,
   411→        new_text,
   412→        new_silks,
   413→        new_direction,
   414→    );
   415→
   416→    // Prepend to tacks array
   417→    pace.tacks.insert(0, new_tack);
   418→
   419→    Ok(())
   420→}
